#include <bits/stdc++.h>
using namespace std;

int n;
bool used[15];
vector<int> ans;

void DFS(int p) {
    if (p > n) {
        for (int i : ans)
            printf("%5d", i);
        printf("\n");
        return ;
    }
    for (int i = 1; i <= n; i++) {
        if (!used[i]) {
            used[i] = true;
            ans.push_back(i);
            DFS(p + 1);
            used[i] = false;
            ans.pop_back();
        }
    }
}

int main() {
    cin >> n;
    DFS(1);
    return 0;
}
